// --- src/codegen/ts-generator.ts ---
import path from "path";
import fs from "fs/promises";
import { capitalize } from "../schema-processor.js";
/**
 * Orchestrates the generation of all user-facing TypeScript files.
 * @param outputDir The directory to write the files to.
 * @param schema The processed schema from the config.
 * @param configPath The original path to the user's config file.
 */
export async function generateTsClient(outputDir, schema, configPath) {
    const runtimeDir = path.join(outputDir, "runtime");
    await fs.mkdir(runtimeDir, { recursive: true });
    // Find the relative path from the generated client to the user's config file.
    const relativeConfigPath = path
        .relative(outputDir, path.resolve(process.cwd(), configPath))
        .replace(/\\/g, "/")
        .replace(/\.ts$/, ""); // Use without extension for clean imports
    await generateTypesFile(outputDir, schema, relativeConfigPath);
    await generateClientFile(outputDir, schema);
    await generateApiProxyHandler(runtimeDir);
    await generateNodeProxyHandler(runtimeDir);
}
async function generateTypesFile(outputDir, schema, configPath) {
    const { nodes, edges } = schema;
    const nodeNames = Object.keys(nodes);
    const zodSchemaImports = nodeNames.map((name) => `${name}Node`).join(", ");
    const importStatement = `import { z } from 'zod';\nimport { ${zodSchemaImports} } from '${configPath}';`;
    const augmentedTypes = nodeNames
        .map((nodeName) => {
        const relatedFields = edges
            .map((edge) => {
            if (edge.source === nodeName) {
                const targetType = capitalize(edge.target);
                const fieldType = edge.cardinality === "one-to-many"
                    ? `z.array(z.lazy(() => ${targetType}Schema))`
                    : `z.lazy(() => ${targetType}Schema)`;
                return `  ${edge.name.forward}: ${fieldType},`;
            }
            if (edge.target === nodeName) {
                const sourceType = capitalize(edge.source);
                const fieldType = edge.cardinality === "one-to-many"
                    ? `z.lazy(() => ${sourceType}Schema)`
                    : `z.array(z.lazy(() => ${sourceType}Schema))`;
                return `  ${edge.name.backward}: ${fieldType},`;
            }
            return null;
        })
            .filter(Boolean)
            .join("\n");
        const baseSchemaName = `${nodeName}Node`;
        const finalSchema = `export const ${capitalize(nodeName)}Schema = ${baseSchemaName}.extend({\n${relatedFields}\n});`;
        const finalType = `export type ${capitalize(nodeName)} = z.infer<typeof ${capitalize(nodeName)}Schema>;`;
        return `${finalSchema}\n${finalType}`;
    })
        .join("\n\n");
    const content = `// Generated by @zgdb/cli\n${importStatement}\n\n${augmentedTypes}\n`;
    await fs.writeFile(path.join(outputDir, "types.ts"), content, "utf8");
}
async function generateClientFile(outputDir, schema) {
    const { nodes } = schema;
    const nodeNames = Object.keys(nodes);
    const typesImport = nodeNames.map(capitalize).join(", ");
    const collectionInterface = `
export interface Collection<T extends {id: string}> extends Iterable<T> {
    add(value: Omit<T, 'id'> & { id: string }): T;
    get(id: string): T | undefined;
    values(): IterableIterator<T>;
}
`;
    const collections = nodeNames
        .map((name) => `    ${name}: Collection<${capitalize(name)}>;`)
        .join("\n");
    const proxyInitializers = nodeNames
        .map((name) => `    client.${name} = new Proxy({} as Collection<${capitalize(name)}>, createApiProxyHandler(db, client, '${name}'));`)
        .join("\n");
    const content = `// Generated by @zgdb/cli
import { PTree } from 'prolly-gunna';
import type { ${typesImport} } from './types.js';
import { createApiProxyHandler } from './runtime/api-proxy-handler.js';

${collectionInterface}

export type ZgDbClient = {
${collections}
};

export function createClient(ptree?: PTree): ZgDbClient {
    const db = ptree || new PTree();
    const client = {} as ZgDbClient;
    
${proxyInitializers}

    return client;
}
`;
    await fs.writeFile(path.join(outputDir, "client.ts"), content, "utf8");
}
async function generateApiProxyHandler(runtimeDir) {
    const content = `// Generated by @zgdb/cli. Runtime logic goes here.
import { PTree } from 'prolly-gunna';
import { ZgDbClient, Collection } from '../client.js';

export function createApiProxyHandler<T extends {id: string}>(ptree: PTree, client: ZgDbClient, nodeName: string): ProxyHandler<Collection<T>> {
    const handler: ProxyHandler<Collection<T>> = {
        get(target, prop, receiver) {
            if (prop === 'add') {
                return (value: T) => {
                    console.log(\`[ADD] Request for \${nodeName} with id: \${value.id}\`);
                    // TODO: PTree insertion/update, serialization, and index update logic.
                    // For now, just return the value for API compatibility.
                    return value;
                }
            }
            if (prop === 'get') {
                return (id: string) => {
                    console.log(\`[GET] Request for \${nodeName} with id: \${id}\`);
                    // TODO: PTree lookup, deserialization, and node proxy creation logic.
                    return undefined;
                }
            }
            if (prop === 'values' || prop === Symbol.iterator) {
                return function* () {
                    console.log(\`[ITERATE] Iterating over \${nodeName}\`);
                    // TODO: PTree scan logic.
                    yield* [];
                }
            }
            return Reflect.get(target, prop, receiver);
        }
    };
    return handler;
}
`;
    await fs.writeFile(path.join(runtimeDir, "api-proxy-handler.ts"), content, "utf8");
}
async function generateNodeProxyHandler(runtimeDir) {
    const content = `// Generated by @zgdb/cli. Runtime logic goes here.
import { PTree } from 'prolly-gunna';
import { ZgDbClient } from '../client.js';
import * as flatbuffers from 'flatbuffers';

export function createNodeProxyHandler(ptree: PTree, client: ZgDbClient, buffer: flatbuffers.ByteBuffer, nodeName: string) {
    return {
        get(target: flatbuffers.ByteBuffer, prop: string | symbol) {
            if (typeof prop === 'symbol') return undefined;
            console.log(\`Accessing '\${prop}' on \${nodeName}\`);
            // TODO: Differentiate between scalar and relation properties.
            // For scalars: use FlatBuffers accessors.
            // For relations: use PTree index lookups.
            return \`value for \${prop}\`;
        }
    };
}
`;
    await fs.writeFile(path.join(runtimeDir, "node-proxy-handler.ts"), content, "utf8");
}
